  2	import { ObjectValidation, Pod } from '../../types/IstioObjects';
  3	import { IRow, ISortBy, SortByDirection, TableVariant } from '@patternfly/react-table';
  4	import {
  5	  Card,
  6	  CardBody,
  7	  CardHeader,
  8	  EmptyState,
  9	  EmptyStateBody,
 10	  EmptyStateVariant,
 11	  Title,
 12	  TitleSizes,
 13	  Tooltip,
 14	  TooltipPosition
 15	} from '@patternfly/react-core';
 16	import { PodStatus } from './PodStatus';
 17	import { kialiStyle } from 'styles/StyleUtils';
 18	import { KialiIcon } from '../../config/KialiIcon';
 19	import { LocalTime } from '../../components/Time/LocalTime';
 20	import { Labels } from '../../components/Label/Labels';
 21	import { PFBadge, PFBadges } from '../../components/Pf/PfBadges';
 22	import { SimpleTable, SortableTh } from 'components/Table/SimpleTable';
 23	import { infoStyle } from 'styles/IconStyle';
 24	import { serverConfig } from '../../config';
 25	
 26	type WorkloadPodsProps = {
 27	  namespace: string;
 28	  pods: Pod[];
 29	  validations: { [key: string]: ObjectValidation };
 30	  workload: string;
 31	};
 32	
 33	const emptyStyle = kialiStyle({
 34	  padding: 0,
 35	  margin: 0
 36	});
 37	
 38	const resourceListStyle = kialiStyle({
 39	  margin: '0 0 0.5rem 0',
 40	  $nest: {
 41	    '& > ul > li > span': {
 42	      float: 'left',
 43	      width: '125px',
 44	      fontWeight: 700
 45	    }
 46	  }
 47	});
 48	
 49	const iconStyle = kialiStyle({
 50	  display: 'inline-block'
 51	});
 52	
 53	export const WorkloadPods: React.FC<WorkloadPodsProps> = (props: WorkloadPodsProps) => {
 54	  const [sortIndex, setSortIndex] = React.useState<number>(0);
 55	  const [sortDirection, setSortDirection] = React.useState<SortByDirection>(SortByDirection.asc);
 56	
 57	  const columns: SortableTh[] = [
 58	    { title: 'Name', sortable: true },
 59	    { title: 'Revision', width: 25, sortable: true },
 60	    { title: 'Status', width: 20, sortable: true }
 61	  ];
 62	
 63	  const sort: ISortBy = { index: sortIndex, direction: sortDirection };
 64	  const onSort = (_event: React.MouseEvent, index: number, direction: SortByDirection): void => {
 65	    setSortIndex(index);
 66	    setSortDirection(direction);
 67	  };
 68	
 69	  const noPods: React.ReactNode = (
 70	    <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle}>
 71	      <EmptyStateBody className={emptyStyle}>No Pods in workload {props.workload}</EmptyStateBody>
 72	    </EmptyState>
 73	  );
 74	
 75	  const sortedPods = [...props.pods].sort((a, b) => {
 76	    const columnKeys = ['name', 'revision', 'status'];
 77	    const key = columnKeys[sortIndex];
 78	
 79	    const aValue = key === 'revision' ? a.annotations?.[serverConfig.istioLabels.injectionLabelRev] ?? '' : a[key];
 80	    const bValue = key === 'revision' ? b.annotations?.[serverConfig.istioLabels.injectionLabelRev] ?? '' : b[key];
 81	
 82	    if (aValue < bValue) return sortDirection === SortByDirection.asc ? -1 : 1;
 83	    if (aValue > bValue) return sortDirection === SortByDirection.asc ? 1 : -1;
 84	    return 0;
 85	  });
 86	
 87	  const rows: IRow[] = sortedPods.map((pod, _podIdx) => {
 88	    let validation: ObjectValidation = {} as ObjectValidation;
 89	
 90	    if (props.validations[pod.name]) {
 91	      validation = props.validations[pod.name];
 92	    }
 93	
 94	    const podProperties = (
 95	      <div key="properties-list" className={resourceListStyle}>
 96	        <ul style={{ listStyleType: 'none' }}>
 97	          <li>
 98	            <span>Created</span>
 99	            <div style={{ display: 'inline-block' }}>
100	              <LocalTime time={pod.createdAt} />
101	            </div>
102	          </li>
103	
104	          <li>
105	            <span>Created By</span>
106	            <div style={{ display: 'inline-block' }}>
107	              {pod.createdBy && pod.createdBy.length > 0
108	                ? pod.createdBy.map(ref => `${ref.name} (${ref.kind})`).join(', ')
109	                : 'Not found'}
110	            </div>
111	          </li>
112	
113	          <li>
114	            <span>Service Account</span>
115	            <div style={{ display: 'inline-block' }}>{pod.serviceAccountName ?? 'Not found'}</div>
116	          </li>
117	
118	          <li>
119	            <span>Istio Init Container</span>
120	            <div style={{ display: 'inline-block' }}>
121	              {pod.istioInitContainers ? pod.istioInitContainers.map(c => `${c.image}`).join(', ') : 'Not found'}
122	            </div>
123	          </li>
124	
125	          <li>
126	            <span>Istio Container</span>
127	            <div style={{ display: 'inline-block' }}>
128	              {pod.istioContainers ? pod.istioContainers.map(c => `${c.image}`).join(', ') : 'Not found'}
129	            </div>
130	          </li>
131	
132	          <li>
133	            <span data-test="protocol">Protocol</span>
134	            <div style={{ display: 'inline-block' }} data-test="protocol-value">
135	              {pod.protocol ? pod.protocol : ''}
136	            </div>
137	          </li>
138	
139	          <li>
140	            <span>Labels</span>
141	            <div style={{ display: 'inline-block' }}>
142	              <Labels labels={pod.labels} expanded={true} />
143	            </div>
144	          </li>
145	        </ul>
146	      </div>
147	    );
148	
149	    return {
150	      cells: [
151	        <span>
152	          <div key="service-icon" className={iconStyle}>
153	            <PFBadge badge={PFBadges.Pod} size="sm" position={TooltipPosition.top} />
154	          </div>
155	
156	          {pod.name}
157	
158	          <Tooltip position={TooltipPosition.right} content={<div style={{ textAlign: 'left' }}>{podProperties}</div>}>
159	            <span data-test="pod-info">
160	              <KialiIcon.Info className={infoStyle} />
161	            </span>
162	          </Tooltip>
163	        </span>,
164	        <span>{pod.annotations?.[serverConfig.istioLabels.injectionLabelRev] ?? 'N/A'}</span>,
165	
166	        <PodStatus proxyStatus={pod.proxyStatus} checks={validation.checks} />
167	      ]
168	    };
169	  });
170	
171	  return (
172	    <Card isCompact={true} id="WorkloadPodsCard">
173	      <CardHeader>
174	        <Title headingLevel="h5" size={TitleSizes.lg}>
175	          Pods
176	        </Title>
177	      </CardHeader>
178	
179	      <CardBody>
180	        <SimpleTable
181	          label="Workload Pod List"
182	          columns={columns}
183	          rows={rows}
184	          variant={TableVariant.compact}
185	          emptyState={noPods}
186	          sortBy={sort}
187	          onSort={onSort}
188	        />
189	      </CardBody>
190	    </Card>
191	  );
192	};

